package main

import (
	"html/template"
	"net/http"
	"strings"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a **great** post!"},
	{Author: "Bob", Content: "I _really_ enjoyed reading this."},
	{Author: "Charlie", Content: "Check out <script>alert('xss')</script> this link!"},
	{Author: "Dave", Content: "**Bold** and _italic_ text here."},
}

func sanitizeAndFormat(content string) template.HTML {
	content = template.HTMLEscapeString(content)
	
	content = formatBold(content)
	content = formatItalic(content)
	
	return template.HTML(content)
}

func formatBold(content string) string {
	parts := strings.Split(content, "**")
	for i := 1; i < len(parts); i += 2 {
		if i < len(parts) {
			parts[i] = "<strong>" + parts[i] + "</strong>"
		}
	}
	return strings.Join(parts, "")
}

func formatItalic(content string) string {
	parts := strings.Split(content, "_")
	for i := 1; i < len(parts); i += 2 {
		if i < len(parts) {
			parts[i] = "<em>" + parts[i] + "</em>"
		}
	}
	return strings.Join(parts, "")
}

type PageData struct {
	Title            string
	FormattedComments []FormattedComment
}

type FormattedComment struct {
	Author          string
	FormattedContent template.HTML
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
    <title>{{.Title}}</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 50px auto; padding: 20px; }
        .comment { border: 1px solid #ddd; padding: 15px; margin: 10px 0; border-radius: 5px; }
        .author { font-weight: bold; color: #333; margin-bottom: 10px; }
        .content { color: #555; line-height: 1.6; }
        h1 { color: #2c3e50; }
    </style>
</head>
<body>
    <h1>{{.Title}}</h1>
    {{range .FormattedComments}}
    <div class="comment">
        <div class="author">{{.Author}}</div>
        <div class="content">{{.FormattedContent}}</div>
    </div>
    {{end}}
</body>
</html>
`))

	formattedComments := make([]FormattedComment, len(comments))
	for i, comment := range comments {
		formattedComments[i] = FormattedComment{
			Author:          comment.Author,
			FormattedContent: sanitizeAndFormat(comment.Content),
		}
	}

	data := PageData{
		Title:            "User Comments",
		FormattedComments: formattedComments,
	}

	tmpl.Execute(w, data)
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}